sys_script_client.script:
function onSubmit() {
    var expiryDate = g_form.getValue('expiry_date');
    if (!expiryDate) return true;

    var today = new Date();
    today.setHours(0, 0, 0, 0);
    var expiry = new Date(expiryDate);

    if (expiry < today) {
        g_form.showFieldMsg('expiry_date', 'Expiry Date cannot be in the past.', 'error');
        return false;
    }
    return true;
}
